    phrases: [{tr: "Bugün müsait misin?", en: "Are you available today?", ipa: "/boo-gewn mew-sah-eet mee-seen/"}, {tr: "Yarın görüşelim mi?", en: "Shall we meet tomorrow?", ipa: "/yah-ruhn gœ-rew-sheh-leem mee/"}, {tr: "Akşam buluşalım.", en: "Let's meet in the evening.", ipa: "/ahk-shahm boo-loo-shah-luhm/"}, {tr: "Saat kaçta?", en: "At what time?", ipa: "/sah-aht kahch-tah/"}, {tr: "Sonra görüşürüz.", en: "See you later.", ipa: "/sohn-rah gœ-rew-shew-rewz/"}, {tr: "Plan tamam.", en: "The plan is set.", ipa: "/plahn tah-mahm/"}],
    grammar: "The ending \"-alım/-elim\" can mean \"let's.\" \"Buluşalım\" means \"let's meet,\" and \"görüşelim\" means \"let's see each other\" or \"let's talk.\" It is friendly and practical for making plans.", practice: ["1. Ask if someone is available today.", "2. Suggest meeting tomorrow.", "3. Say let's meet in the evening.", "4. Ask at what time.", "5. Say the plan is set."],
