    phrases: [{tr: "Merhaba, yardım edebilir misiniz?", en: "Hello, can you help?", ipa: "/mehr-hah-bah yahr-duhm eh-deh-bee-leer mee-see-neez/"}, {tr: "Bu adrese gitmek istiyorum.", en: "I want to go to this address.", ipa: "/boo ahd-reh-seh geet-mek ees-tee-yo-room/"}, {tr: "Ne önerirsiniz?", en: "What do you recommend?", ipa: "/neh œ-neh-reer-see-neez/"}, {tr: "Hesap lütfen.", en: "The bill, please.", ipa: "/heh-sahp lew-tfen/"}, {tr: "İndirim var mı?", en: "Is there a discount?", ipa: "/een-dee-reem vahr muh/"}, {tr: "Türkçe az biliyorum ama öğreniyorum.", en: "I know a little Turkish, but I am learning.", ipa: "/tewrk-cheh ahz bee-lee-yo-room ah-mah œ-reh-nee-yo-room/"}],
    grammar: "Today's goal is combining chunks rather than learning one new rule. Turkish travelers' phrases are powerful because you can swap one word inside a familiar structure. For example, \"Bu adrese gitmek istiyorum\" can become \"Otele gitmek istiyorum\" or \"Müzeye gitmek istiyorum.\"", practice: ["1. Start a conversation by asking for help.", "2. Tell someone you want to go to an address.", "3. Ask a restaurant server for a recommendation.", "4. Ask for the bill.", "5. Say you know a little Turkish but are learning."],
